// Hidden file input for uploading a custom SVG dot shape. On load, parse the
// SVG into a normalized outline, switch Shape to 'custom', and re-render.
const inputSVG = document.createElement("input");
inputSVG.type = "file";
inputSVG.accept = "image/svg+xml, .svg";
inputSVG.style = "display:none";
document.body.appendChild(inputSVG);

inputSVG.addEventListener("change", () => {
  const file = inputSVG.files[0];
  if (!file) return;
  const reader = new FileReader();
  reader.onload = () => {
    if (loadCustomShapeFromSVG(String(reader.result))) {
      params.shape = "custom";
      if (typeof pane !== "undefined" && pane) pane.refresh();
      if (typeof manager !== "undefined") manager.render();
    } else {
      alert("Could not read a shape from that SVG.");
    }
  };
  reader.readAsText(file);
  inputSVG.value = ""; // allow re-uploading the same file
});

// Drag the sphere with the mouse: horizontal motion spins it around Y, vertical
// around X. Only active in sphere mode. Attaches once per canvas.
let dragAttached = false;
const attachSphereDrag = (canvas) => {
  if (dragAttached || !canvas) return;
  dragAttached = true;

  let dragging = false;
  let lastX = 0;
  let lastY = 0;
  const wrap180 = (a) => ((((a + 180) % 360) + 360) % 360) - 180;

  canvas.addEventListener("pointerdown", (e) => {
    if (params.mode3D !== "sphere") return;
    dragging = true;
    lastX = e.clientX;
    lastY = e.clientY;
    canvas.setPointerCapture(e.pointerId);
    canvas.style.cursor = "grabbing";
  });

  canvas.addEventListener("pointermove", (e) => {
    if (!dragging) return;
    // Scale screen px → degrees by the on-screen canvas size so it feels 1:1.
    const rect = canvas.getBoundingClientRect();
    const sx = 360 / Math.max(1, rect.width);
    const sy = 360 / Math.max(1, rect.height);
    params.rotY = wrap180(params.rotY + (e.clientX - lastX) * sx);
    params.rotX = wrap180(params.rotX - (e.clientY - lastY) * sy);
    lastX = e.clientX;
    lastY = e.clientY;
    if (typeof manager !== "undefined") manager.render();
  });

  const endDrag = (e) => {
    if (!dragging) return;
    dragging = false;
    if (e && e.pointerId != null && canvas.hasPointerCapture(e.pointerId)) {
      canvas.releasePointerCapture(e.pointerId);
    }
    canvas.style.cursor = params.mode3D === "sphere" ? "grab" : "default";
  };
  canvas.addEventListener("pointerup", endDrag);
  canvas.addEventListener("pointercancel", endDrag);
  canvas.style.cursor = params.mode3D === "sphere" ? "grab" : "default";
};

const sketch = ({ canvas, context, width, height }) => {
  elCanvas = canvas;
  attachSphereDrag(canvas);
  if (srcType == "video") {
    media.addEventListener(
      "loadedmetadata",
      function (e) {
        const ratio = this.videoHeight / this.videoWidth;
        const settings2 = {
          dimensions: [canvW, canvW * ratio],
        };

        mediaCanvas.width = canvW;
        mediaCanvas.height = canvW * ratio;

        manager.loadAndRun(sketch, settings2);
        URL.revokeObjectURL(media.src);
      },
      false,
    );
  } else if (srcType == "image") {
    media.onload = () => {
      ratio = media.height / media.width;
      const settings2 = {
        dimensions: [canvW, canvW * ratio],
      };

      mediaCanvas.width = canvW;
      mediaCanvas.height = canvW * ratio;
      manager.loadAndRun(sketch, settings2);
      URL.revokeObjectURL(media.src);
    };
  }

  return svg(({ canvas, context, width, height, frame, exporting }) => {
    // Still images pause the loop; mouse drag re-renders on demand.
    if (srcType == "image") {
      if (typeof manager != "undefined") manager.pause();
    }

    const Inv = params.Inv ? 1 : 0;
    mediaContext.filter = `invert(${Inv}) brightness(${params.BR}%) contrast(${params.CR}%) saturate(${params.Sat}%) blur(${params.Blur}px)`;
    mediaContext.drawImage(media, 0, 0, width, height);
    pixels = mediaContext.getImageData(0, 0, width, height).data;

    // Bypass the effect and show the (filtered) original photo.
    if (params.showOriginal) {
      context.fillStyle = "black";
      context.fillRect(0, 0, width, height);
      context.drawImage(mediaCanvas, 0, 0, width, height);
      return;
    }

    // Background plate. On canvas a light-gray backdrop sits behind the screen
    // so the marks read clearly; on export/copy the background is skipped
    // entirely so the SVG contains only the halftone marks (no rectangle).
    if (!exporting) {
      context.fillStyle = "#e6e6e6";
      context.fillRect(0, 0, width, height);

      // White disc behind the sphere so the ball reads as a solid surface.
      // Also screen-only — never exported.
      if (params.mode3D === "sphere") {
        context.fillStyle = "#ffffff";
        context.beginPath();
        context.arc(width / 2, height / 2, params.sphereRadius, 0, Math.PI * 2);
        context.fill();
      }
    }

    const cell = Math.max(2, params.cellSize);
    if (params.mode3D === "sphere") {
      drawSphereScreen(context, width, height, cell, frame);
    } else if (params.screen === "line") {
      drawLineScreen(context, width, height, cell, params.angle);
    } else {
      drawColorScreen(context, width, height, cell, params.angle);
    }

    // Optional grid overlay: the screen lattice the dots/lines are placed on.
    // In sphere mode it draws the silhouette circle instead of the flat lattice.
    if (params.showGrid) {
      if (params.mode3D === "sphere") {
        // Silhouette must match the sphere, which is always canvas-centred.
        context.save();
        context.strokeStyle = "rgba(255,0,0,0.4)";
        context.lineWidth = 1;
        context.beginPath();
        context.arc(width / 2, height / 2, params.sphereRadius, 0, Math.PI * 2);
        context.stroke();
        context.restore();
      } else {
        drawGrid(context, width, height, cell, params.angle);
      }
    }

    // Live center guide: a red crosshair at the arrangement center while the
    // "Center" control is being dragged.
    if (showCenterGuide) {
      drawCenterGuide(context, width, height);
    }
  }, exportType);
};

// The arrangement/falloff center in canvas px (params.center is normalized).
const getCenter = (width, height) => [
  width * params.center.x,
  height * params.center.y,
];

// Distance from (cx,cy) to the farthest canvas corner — used to normalize the
// radial falloff and to know how far out the radial rings must reach.
const maxCornerDist = (width, height, cx, cy) =>
  Math.max(
    Math.hypot(cx, cy),
    Math.hypot(width - cx, cy),
    Math.hypot(cx, height - cy),
    Math.hypot(width - cx, height - cy),
  );

// --- Average the source color over one halftone cell -----------------------
// Returns [r,g,b] in 0..255 for the cell centered near (cx, cy).
const sampleCell = (cx, cy, cell, width, height) => {
  let sr = 0;
  let sg = 0;
  let sb = 0;
  let n = 0;
  const step = Math.max(1, Math.floor(cell / 3));
  const half = cell / 2;
  for (let y = cy - half; y <= cy + half; y += step) {
    for (let x = cx - half; x <= cx + half; x += step) {
      if (x < 0 || y < 0 || x >= width || y >= height) continue;
      const c = getColor(x, y, pixels);
      sr += c[0];
      sg += c[1];
      sb += c[2];
      n++;
    }
  }
  if (n === 0) return getColor(cx, cy, pixels);
  return [sr / n, sg / n, sb / n];
};

// Apply the gamma/tone curve to a coverage value in [0,1].
const tone = (v) => {
  const g = params.gamma <= 0 ? 1 : params.gamma;
  return Math.pow(Math.min(1, Math.max(0, v)), g);
};

// Easing curves used to shape the radial size falloff. Each maps a normalized
// distance t in [0,1] to an eased value in [0,1]. 'linear' is plain radial.
const easings = {
  linear: (t) => t,
  easeInQuad: (t) => t * t,
  easeOutQuad: (t) => t * (2 - t),
  easeInOutQuad: (t) => (t < 0.5 ? 2 * t * t : -1 + (4 - 2 * t) * t),
  easeInCubic: (t) => t * t * t,
  easeOutCubic: (t) => 1 - Math.pow(1 - t, 3),
  easeInOutCubic: (t) =>
    t < 0.5 ? 4 * t * t * t : 1 - Math.pow(-2 * t + 2, 3) / 2,
  easeInQuart: (t) => t * t * t * t,
  easeOutQuart: (t) => 1 - Math.pow(1 - t, 4),
  easeInOutQuart: (t) =>
    t < 0.5 ? 8 * t * t * t * t : 1 - Math.pow(-2 * t + 2, 4) / 2,
  easeInQuint: (t) => t * t * t * t * t,
  easeOutQuint: (t) => 1 - Math.pow(1 - t, 5),
  easeInOutQuint: (t) =>
    t < 0.5 ? 16 * t * t * t * t * t : 1 - Math.pow(-2 * t + 2, 5) / 2,
  easeInSine: (t) => 1 - Math.cos((t * Math.PI) / 2),
  easeOutSine: (t) => Math.sin((t * Math.PI) / 2),
  easeInOutSine: (t) => -(Math.cos(Math.PI * t) - 1) / 2,
  easeInExpo: (t) => (t <= 0 ? 0 : Math.pow(2, 10 * t - 10)),
  easeOutExpo: (t) => (t >= 1 ? 1 : 1 - Math.pow(2, -10 * t)),
  easeInOutExpo: (t) =>
    t <= 0
      ? 0
      : t >= 1
        ? 1
        : t < 0.5
          ? Math.pow(2, 20 * t - 10) / 2
          : (2 - Math.pow(2, -20 * t + 10)) / 2,
  easeInCirc: (t) => 1 - Math.sqrt(1 - t * t),
  easeOutCirc: (t) => Math.sqrt(1 - Math.pow(t - 1, 2)),
  easeInOutCirc: (t) =>
    t < 0.5
      ? (1 - Math.sqrt(1 - Math.pow(2 * t, 2))) / 2
      : (Math.sqrt(1 - Math.pow(-2 * t + 2, 2)) + 1) / 2,
  easeInBack: (t) => 2.70158 * t * t * t - 1.70158 * t * t,
  easeOutBack: (t) =>
    1 + 2.70158 * Math.pow(t - 1, 3) + 1.70158 * Math.pow(t - 1, 2),
  easeInOutBack: (t) => {
    const c = 1.70158 * 1.525;
    return t < 0.5
      ? (Math.pow(2 * t, 2) * ((c + 1) * 2 * t - c)) / 2
      : (Math.pow(2 * t - 2, 2) * ((c + 1) * (2 * t - 2) + c) + 2) / 2;
  },
  easeInElastic: (t) =>
    t <= 0
      ? 0
      : t >= 1
        ? 1
        : -Math.pow(2, 10 * t - 10) *
          Math.sin((t * 10 - 10.75) * ((2 * Math.PI) / 3)),
  easeOutElastic: (t) =>
    t <= 0
      ? 0
      : t >= 1
        ? 1
        : Math.pow(2, -10 * t) *
            Math.sin((t * 10 - 0.75) * ((2 * Math.PI) / 3)) +
          1,
  easeOutBounce: (t) => {
    const n1 = 7.5625;
    const d1 = 2.75;
    if (t < 1 / d1) return n1 * t * t;
    if (t < 2 / d1) return n1 * (t -= 1.5 / d1) * t + 0.75;
    if (t < 2.5 / d1) return n1 * (t -= 2.25 / d1) * t + 0.9375;
    return n1 * (t -= 2.625 / d1) * t + 0.984375;
  },
  easeInBounce: (t) => 1 - easings.easeOutBounce(1 - t),
};

// Map a coverage value [0,1] through the currently selected decay curve. This
// reshapes the brightness->size response: 'linear' is the plain mapping, the
// ease variants push tones toward the shadows or highlights.
const applyDecay = (t) => {
  const fn = easings[params.decay] || easings.linear;
  return Math.min(1, Math.max(0, fn(Math.min(1, Math.max(0, t)))));
};

// Custom shape outline, set when the user uploads an SVG: an array of {x,y}
// points normalized to roughly -1..1 around the origin, tip pointing along +x
// (so it angles radially like the triangle). Empty until an SVG is loaded.
let customShapePoints = [];

// Parse an uploaded SVG string into a normalized polygon outline for use as a
// custom dot shape. Every <path>/<polygon>/<polyline>/<rect>/<circle>/...
// geometry element is sampled into points via the browser's path-length API,
// then the combined outline is centered and scaled to fit in a unit circle.
// The shape is rotated so "up" in the SVG becomes the radial tip (+x local).
const loadCustomShapeFromSVG = (svgText) => {
  const doc = new DOMParser().parseFromString(svgText, "image/svg+xml");
  const svgEl = doc.querySelector("svg");
  if (!svgEl) return false;

  // Mount off-screen so getTotalLength/getPointAtLength work (needs layout).
  const holder = document.createElement("div");
  holder.style.cssText =
    "position:absolute;width:0;height:0;overflow:hidden;left:-9999px";
  holder.appendChild(svgEl);
  document.body.appendChild(holder);

  const geoms = svgEl.querySelectorAll(
    "path, polygon, polyline, rect, circle, ellipse, line",
  );
  const raw = [];
  geoms.forEach((g) => {
    if (typeof g.getTotalLength !== "function") return;
    const len = g.getTotalLength();
    if (!len || !isFinite(len)) return;
    // Sample proportional to length; cap so very long paths stay reasonable.
    const steps = Math.max(12, Math.min(400, Math.round(len / 2)));
    for (let i = 0; i <= steps; i++) {
      const p = g.getPointAtLength((len * i) / steps);
      raw.push({ x: p.x, y: p.y });
    }
  });
  document.body.removeChild(holder);

  if (raw.length < 3) return false;

  // Center on the bounding-box middle and scale to fit a unit circle.
  let minX = Infinity;
  let minY = Infinity;
  let maxX = -Infinity;
  let maxY = -Infinity;
  for (const p of raw) {
    if (p.x < minX) minX = p.x;
    if (p.y < minY) minY = p.y;
    if (p.x > maxX) maxX = p.x;
    if (p.y > maxY) maxY = p.y;
  }
  const cx = (minX + maxX) / 2;
  const cy = (minY + maxY) / 2;
  const half = Math.max(maxX - minX, maxY - minY) / 2 || 1;

  customShapePoints = raw.map((p) => ({
    // SVG y is down; negate so the shape's "up" becomes the radial tip after the
    // local +x rotation. Swap axes so up (−y) maps to +x (the tip direction).
    x: -(p.y - cy) / half,
    y: (p.x - cx) / half,
  }));
  return true;
};

// Unit-radius vertex list for an angled polygon shape, tip pointing along the
// radial direction `baseAngle`. Returns points in canvas px around (x,y).
// Used by diamond/star/triangle/custom so they all orient like the triangle.
const shapeVertices = (shape, x, y, r, baseAngle) => {
  const pts = [];
  const add = (lx, ly) => {
    // local (lx,ly): +x = radial-out (tip), rotated by baseAngle into canvas.
    const ca = Math.cos(baseAngle);
    const sa = Math.sin(baseAngle);
    pts.push({
      x: x + (lx * ca - ly * sa) * r,
      y: y + (lx * sa + ly * ca) * r,
    });
  };
  if (shape === "square") {
    // Square as a polygon so it can be angled (the axis-aligned fast path in
    // drawDot is used when the orientation is the default radial mode).
    add(0.85, 0.85);
    add(-0.85, 0.85);
    add(-0.85, -0.85);
    add(0.85, -0.85);
  } else if (shape === "triangle") {
    for (let k = 0; k < 3; k++) {
      const a = (k * 2 * Math.PI) / 3;
      add(Math.cos(a), Math.sin(a));
    }
  } else if (shape === "diamond") {
    add(1, 0);
    add(0, 0.7);
    add(-1, 0);
    add(0, -0.7);
  } else if (shape === "star") {
    // 5-point star, first point on the tip (radial-out).
    const spikes = 5;
    const inner = 0.45;
    for (let k = 0; k < spikes * 2; k++) {
      const rad = k % 2 === 0 ? 1 : inner;
      const a = (k * Math.PI) / spikes;
      add(Math.cos(a) * rad, Math.sin(a) * rad);
    }
  } else if (shape === "custom") {
    for (let k = 0; k < customShapePoints.length; k++) {
      add(customShapePoints[k].x, customShapePoints[k].y);
    }
  }
  return pts;
};

// Stable pseudo-random angle [0,2π) derived from a dot's position, so each dot
// keeps the same random orientation across frames and the SVG export pass.
const randomAngleAt = (x, y) => {
  const s = Math.sin(x * 12.9898 + y * 78.233) * 43758.5453;
  return (s - Math.floor(s)) * Math.PI * 2;
};

// The orientation a shape should point. 'center' = radial (out of the
// arrangement centre, like the triangle); 'random' = a stable per-dot angle;
// 'fixed' = the same fixedAngle for every dot.
const shapeBaseAngle = (x, y, centerX, centerY) => {
  if (params.shapeAngle === "random") return randomAngleAt(x, y);
  if (params.shapeAngle === "fixed") return (params.fixedAngle * Math.PI) / 180;
  return x === centerX && y === centerY
    ? -Math.PI / 2
    : Math.atan2(y - centerY, x - centerX);
};

// Draw one dot of given coverage [0,1] at (x,y) for a given cell pitch.
// Angled shapes (square/triangle/diamond/star/custom) point either radially out
// of the arrangement center or at a random per-dot angle (params.shapeAngle).
const drawDot = (context, x, y, coverage, cell, color, centerX, centerY) => {
  const cov = tone(coverage);
  if (cov <= 0.001) return;
  // dot radius so that coverage==1 just fills the cell diagonally.
  const maxR = (cell / 2) * Math.SQRT2 * params.dotScale;
  const r = maxR * Math.sqrt(cov); // area-proportional growth
  context.fillStyle = color;
  context.beginPath();
  if (params.shape === "circle") {
    context.arc(x, y, r, 0, Math.PI * 2);
  } else if (params.shape === "square" && params.shapeAngle === "center") {
    // Axis-aligned fast path for the default square (no rotation needed).
    const s = r; // half-side
    context.rect(x - s, y - s, s * 2, s * 2);
  } else {
    const baseAngle = shapeBaseAngle(x, y, centerX, centerY);
    const verts = shapeVertices(params.shape, x, y, r, baseAngle);
    if (verts.length < 2) {
      // No custom shape loaded yet — fall back to a circle.
      context.arc(x, y, r, 0, Math.PI * 2);
    } else {
      for (let k = 0; k < verts.length; k++) {
        if (k === 0) context.moveTo(verts[k].x, verts[k].y);
        else context.lineTo(verts[k].x, verts[k].y);
      }
      context.closePath();
    }
  }
  context.fill();
};

// Iterate a row/col screen grid rotated by `angleDeg` around (ccx, ccy),
// calling cb(cx, cy) for every dot center that falls inside the canvas.
const forEachScreenDot = (width, height, cell, angleDeg, ccx, ccy, cb) => {
  const a = (angleDeg * Math.PI) / 180;
  const cos = Math.cos(a);
  const sin = Math.sin(a);
  // Diagonal extent so the rotated grid covers the whole canvas even when the
  // pivot sits in a corner.
  const diag =
    Math.ceil((2 * Math.sqrt(width * width + height * height)) / cell) + 2;
  for (let j = -diag; j <= diag; j++) {
    for (let i = -diag; i <= diag; i++) {
      const u = i * cell;
      const v = j * cell;
      const x = ccx + u * cos - v * sin;
      const y = ccy + u * sin + v * cos;
      if (x < -cell || y < -cell || x > width + cell || y > height + cell)
        continue;
      cb(x, y);
    }
  }
};

// Iterate a radial screen grid: concentric rings around (ccx, ccy), spaced
// `cell` apart, with dots spaced ~`cell` along each ring so density stays
// even. `angleDeg` rotates where each ring starts. cb(cx, cy) per dot.
const forEachRadialDot = (width, height, cell, angleDeg, ccx, ccy, cb) => {
  const a0 = (angleDeg * Math.PI) / 180;
  const maxR = maxCornerDist(width, height, ccx, ccy);
  cb(ccx, ccy); // the single dot at the very center
  for (let r = cell; r <= maxR + cell; r += cell) {
    // Dots per ring so arc spacing along the circumference stays ~cell.
    const count = Math.max(1, Math.round((2 * Math.PI * r) / cell));
    for (let k = 0; k < count; k++) {
      const t = a0 + (k / count) * Math.PI * 2;
      const x = ccx + Math.cos(t) * r;
      const y = ccy + Math.sin(t) * r;
      if (x < -cell || y < -cell || x > width + cell || y > height + cell)
        continue;
      cb(x, y);
    }
  }
};

// Compute the dot/line coverage [0,1] and source color for the cell at (cx,cy).
// Shared by the dot-grid and line-screen renderers.
const sampleCoverageColor = (cx, cy, cell, width, height) => {
  const [r, g, b] = sampleCell(cx, cy, cell, width, height);
  const lum = (0.299 * r + 0.587 * g + 0.114 * b) / 255;

  // Base coverage from pixel brightness, then reshape it with the decay curve
  // so the bright->dark size response can be eased rather than linear.
  const base = params.sizeBy === "dark" ? 1 - lum : lum;
  const coverage = applyDecay(base);

  // Mono mode swaps the sampled color for the single ink color; the coverage
  // (and therefore dot/line size) still follows the image as usual.
  const color =
    params.colorMode === "mono"
      ? params.inkColor
      : `rgb(${Math.round(r)},${Math.round(g)},${Math.round(b)})`;
  return { coverage, color, r, g, b };
};

// --- RGB colored-dot halftone: one screen, each dot in the cell's own color -
// The dot centers come from either the row/col grid or the radial rings,
// depending on params.arrange.
const drawColorScreen = (context, width, height, cell, angle) => {
  const [ccx, ccy] = getCenter(width, height);

  const emit = (cx, cy) => {
    const { coverage, color } = sampleCoverageColor(
      cx,
      cy,
      cell,
      width,
      height,
    );
    drawDot(context, cx, cy, coverage, cell, color, ccx, ccy);
  };

  if (params.arrange === "radial") {
    forEachRadialDot(width, height, cell, angle, ccx, ccy, emit);
  } else {
    forEachScreenDot(width, height, cell, angle, ccx, ccy, emit);
  }
};

// --- 3D sphere screen ------------------------------------------------------
// The ENTIRE flat halftone is drawn by the normal flat renderers (so every
// control — screen type, arrangement, angle, lines, shapes — works), but each
// path coordinate they emit is intercepted and bent onto the sphere first. The
// flat result is treated as a decal painted on the front of the ball: the image
// centre pins to the front pole, and rotating turns the whole decal with the
// surface. Marks are warped point-by-point, so dots/triangles/lines curve along
// the surface. Everything stays 2D path primitives, so SVG export still works.

// Rotate a point around Y, then X, then Z (radians).
const rotatePoint = (p, ax, ay, az) => {
  let { x, y, z } = p;
  let c = Math.cos(ay);
  let s = Math.sin(ay);
  [x, z] = [x * c + z * s, -x * s + z * c];
  c = Math.cos(ax);
  s = Math.sin(ax);
  [y, z] = [y * c - z * s, y * s + z * c];
  c = Math.cos(az);
  s = Math.sin(az);
  [x, y] = [x * c - y * s, x * s + y * c];
  return { x, y, z };
};

// Paint a flat point onto the FRONT of the sphere like a decal. A flat offset
// (nx, ny) from the image centre — each in roughly -1..1 — is bent onto the
// sphere as an angular offset from the front pole (+z): centre sits at the
// front, edges curve around toward the silhouette. `wrap` is how far the decal
// spreads: 1 = the image reaches the equator (a full front hemisphere).
const flatToFrontCap = (nx, ny, wrap) => {
  const rho = Math.hypot(nx, ny); // distance from image centre (0 at middle)
  const phi = rho * (Math.PI / 2) * wrap; // angle from the front pole
  const k = rho < 1e-6 ? 1 : Math.sin(phi) / rho; // bend factor (1 at centre)
  return {
    x: nx * k,
    y: ny * k,
    z: Math.cos(phi), // toward the camera at the front pole
  };
};

// A proxy 2D context that bends every path coordinate the flat renderers emit
// onto the sphere before forwarding to the real context. Non-geometry calls
// (fillStyle, fill, save, etc.) pass straight through, so the real flat drawing
// code runs unchanged. `arc` is approximated by a polygon so circular dots also
// curve along the surface. Sub-paths that fall on the back hemisphere are
// dropped (backface culling).
const makeSphereContext = (real, width, height, frame) => {
  const ccx = width / 2; // sphere always centred on the canvas
  const ccy = height / 2;
  const R = params.sphereRadius;
  const halfMin = Math.min(width, height) / 2;
  // wrap can exceed 1 to push the decal past the equator onto the back: at
  // wrap=1 the image edge reaches the silhouette (front hemisphere), at wrap=2
  // it reaches the back pole (the image covers the whole sphere).
  const wrap = Math.max(0.001, params.wrap);

  const ax = (params.rotX * Math.PI) / 180;
  const ay = (params.rotY * Math.PI) / 180;
  const az = (params.rotZ * Math.PI) / 180;

  // Flat image px -> screen px on the sphere, carrying depth for culling.
  const project = (px, py) => {
    const nnx = (px - width / 2) / halfMin;
    const nny = (py - height / 2) / halfMin;
    const c = flatToFrontCap(nnx, nny, wrap);
    const p = rotatePoint(c, ax, ay, az);
    // Orthographic projection (no perspective): x/y straight, z kept for culling.
    return { x: ccx + R * p.x, y: ccy + R * p.y, z: p.z };
  };

  // Current sub-path as flat points; emitted (bent) on fill so we can cull and
  // tessellate straight segments into short curved ones along the surface.
  let sub = [];
  const SEG = Math.max(2, R / 80); // max flat segment length before subdividing

  const moveTo = (x, y) => sub.push({ x, y, m: true });
  const lineTo = (x, y) => sub.push({ x, y, m: false });

  const flush = (close) => {
    if (sub.length < 2) {
      sub = [];
      return;
    }
    // Tessellate long straight segments so they bend smoothly on the sphere.
    const dense = [];
    for (let i = 0; i < sub.length; i++) {
      const pt = sub[i];
      if (i === 0 || pt.m) {
        dense.push({ x: pt.x, y: pt.y, m: pt.m });
        continue;
      }
      const prev = sub[i - 1];
      const dist = Math.hypot(pt.x - prev.x, pt.y - prev.y);
      const n = Math.max(1, Math.ceil(dist / SEG));
      for (let k = 1; k <= n; k++) {
        const t = k / n;
        dense.push({
          x: prev.x + (pt.x - prev.x) * t,
          y: prev.y + (pt.y - prev.y) * t,
          m: false,
        });
      }
    }
    // Project, dropping any point on the back hemisphere; a back point breaks
    // the sub-path (so partly-visible marks are clipped, not smeared).
    let started = false;
    let drew = false;
    for (let i = 0; i < dense.length; i++) {
      const sp = project(dense[i].x, dense[i].y);
      if (sp.z < 0) {
        started = false;
        continue;
      }
      if (!started || dense[i].m) {
        real.moveTo(sp.x, sp.y);
        started = true;
      } else {
        real.lineTo(sp.x, sp.y);
      }
      drew = true;
    }
    if (drew && close) real.closePath();
    sub = [];
  };

  // Proxy: geometry is captured/bent; everything else forwards to `real`.
  return {
    set fillStyle(v) {
      real.fillStyle = v;
    },
    get fillStyle() {
      return real.fillStyle;
    },
    set strokeStyle(v) {
      real.strokeStyle = v;
    },
    set lineWidth(v) {
      real.lineWidth = v;
    },
    beginPath() {
      sub = [];
      real.beginPath();
    },
    moveTo,
    lineTo,
    rect(x, y, w, h) {
      moveTo(x, y);
      lineTo(x + w, y);
      lineTo(x + w, y + h);
      lineTo(x, y + h);
      sub.push({ x, y, m: false }); // close back to start
    },
    arc(cx, cy, r, a0, a1) {
      // Approximate the circle as a polygon of flat points (then bent).
      const steps = Math.max(8, Math.ceil((r * Math.PI) / 4));
      for (let i = 0; i <= steps; i++) {
        const a = a0 + ((a1 - a0) * i) / steps;
        const x = cx + Math.cos(a) * r;
        const y = cy + Math.sin(a) * r;
        if (i === 0) moveTo(x, y);
        else lineTo(x, y);
      }
    },
    closePath() {
      // Defer the actual close to flush() so culling stays correct.
      if (sub.length) sub.push({ ...sub[0], m: false });
    },
    fill() {
      real.beginPath();
      flush(true);
      real.fill();
    },
    stroke() {
      real.beginPath();
      flush(false);
      real.stroke();
    },
    save() {
      real.save();
    },
    restore() {
      real.restore();
    },
  };
};

// Draw the whole flat halftone through the bending proxy so it lands on the
// sphere. The flat renderers run unchanged, so all halftone controls apply.
const drawSphereScreen = (context, width, height, cell, frame) => {
  const proxy = makeSphereContext(context, width, height, frame);
  if (params.screen === "line") {
    drawLineScreen(proxy, width, height, cell, params.angle);
  } else {
    drawColorScreen(proxy, width, height, cell, params.angle);
  }
};

// --- Variable-thickness line screen ----------------------------------------
// Grid arrangement: rows of straight lines rotated by `angle`. Radial
// arrangement: concentric rings around the center. Either way each line is
// emitted as a filled ribbon whose half-thickness at each step follows the
// local tone, like a classic line-screen halftone.
const drawLineScreen = (context, width, height, cell, angle) => {
  const [ccx, ccy] = getCenter(width, height);

  if (params.arrange === "radial") {
    drawRingScreen(context, width, height, cell, angle, ccx, ccy);
    return;
  }

  const a = (angle * Math.PI) / 180;
  const cos = Math.cos(a);
  const sin = Math.sin(a);
  // u runs along each line, v steps between lines (perpendicular).
  const diag =
    Math.ceil((2 * Math.sqrt(width * width + height * height)) / cell) + 2;
  // Sample fine enough along the line that thickness tracks the image smoothly.
  const step = Math.max(2, cell / 2);
  const span =
    Math.ceil((2 * Math.sqrt(width * width + height * height)) / step) + 2;
  // coverage==1 fills the gap between adjacent lines (half-thickness = cell/2).
  const maxHalf = (cell / 2) * params.dotScale;

  // Perpendicular offset direction (unit), used to give each line its thickness.
  const px = -sin;
  const py = cos;

  for (let j = -diag; j <= diag; j++) {
    const v = j * cell;
    // Collect on-canvas samples for this row: position, half-thickness, color.
    const pts = [];
    for (let s = -span; s <= span; s++) {
      const u = s * step;
      const x = ccx + u * cos - v * sin;
      const y = ccy + u * sin + v * cos;
      if (x < -cell || y < -cell || x > width + cell || y > height + cell) {
        if (pts.length) pts.push(null); // break the ribbon across gaps
        continue;
      }
      const { coverage, color } = sampleCoverageColor(
        x,
        y,
        cell,
        width,
        height,
      );
      const half = maxHalf * tone(coverage); // line half-thickness here
      pts.push({ x, y, half, color });
    }
    // Emit each adjacent pair as a colored trapezoid so both thickness AND hue
    // vary continuously along the line.
    for (let k = 0; k < pts.length - 1; k++) {
      const p0 = pts[k];
      const p1 = pts[k + 1];
      if (!p0 || !p1) continue;
      if (p0.half <= 0.05 && p1.half <= 0.05) continue;
      context.fillStyle = p0.color;
      context.beginPath();
      context.moveTo(p0.x + px * p0.half, p0.y + py * p0.half);
      context.lineTo(p1.x + px * p1.half, p1.y + py * p1.half);
      context.lineTo(p1.x - px * p1.half, p1.y - py * p1.half);
      context.lineTo(p0.x - px * p0.half, p0.y - py * p0.half);
      context.closePath();
      context.fill();
    }
  }
};

// Radial counterpart of the line screen: concentric rings around (ccx, ccy),
// each ring a ribbon whose thickness follows the local tone. The thickness is
// applied along the ring's radial normal, so rings swell toward/away from the
// center. `angle` rotates where each ring's sampling starts.
const drawRingScreen = (context, width, height, cell, angle, ccx, ccy) => {
  const a0 = (angle * Math.PI) / 180;
  const maxDist = maxCornerDist(width, height, ccx, ccy); // how far out the rings must reach
  const maxHalf = (cell / 2) * params.dotScale;
  const step = Math.max(2, cell / 2); // target arc length between samples

  for (let r = cell; r <= maxDist + cell; r += cell) {
    // Enough angular samples that arc spacing stays ~step even on big rings.
    const steps = Math.max(8, Math.ceil((2 * Math.PI * r) / step));
    const pts = [];
    for (let s = 0; s <= steps; s++) {
      const t = a0 + (s / steps) * Math.PI * 2;
      const nx = Math.cos(t); // radial normal — the thickness direction
      const ny = Math.sin(t);
      const x = ccx + nx * r;
      const y = ccy + ny * r;
      if (x < -cell || y < -cell || x > width + cell || y > height + cell) {
        if (pts.length) pts.push(null); // break the ribbon across gaps
        continue;
      }
      const { coverage, color } = sampleCoverageColor(
        x,
        y,
        cell,
        width,
        height,
      );
      const half = maxHalf * tone(coverage); // ring half-thickness here
      pts.push({ x, y, half, color, nx, ny });
    }
    // Emit each adjacent pair as a colored trapezoid so both thickness AND hue
    // vary continuously around the ring.
    for (let k = 0; k < pts.length - 1; k++) {
      const p0 = pts[k];
      const p1 = pts[k + 1];
      if (!p0 || !p1) continue;
      if (p0.half <= 0.05 && p1.half <= 0.05) continue;
      context.fillStyle = p0.color;
      context.beginPath();
      context.moveTo(p0.x + p0.nx * p0.half, p0.y + p0.ny * p0.half);
      context.lineTo(p1.x + p1.nx * p1.half, p1.y + p1.ny * p1.half);
      context.lineTo(p1.x - p1.nx * p1.half, p1.y - p1.ny * p1.half);
      context.lineTo(p0.x - p0.nx * p0.half, p0.y - p0.ny * p0.half);
      context.closePath();
      context.fill();
    }
  }
};

// Overlay showing the halftone screen lattice the marks sit on. For the grid
// arrangement it draws the rotated row/col lines; for radial it draws the
// concentric rings. Matches the spacing/rotation used by the screen iterators.
const drawGrid = (context, width, height, cell, angle) => {
  const [ccx, ccy] = getCenter(width, height);
  const maxDist = maxCornerDist(width, height, ccx, ccy);

  context.save();
  context.strokeStyle = "rgba(255,0,0,0.4)";
  context.lineWidth = 1;

  if (params.arrange === "radial") {
    // Concentric rings, same radii as forEachRadialDot / drawRingScreen.
    for (let r = cell; r <= maxDist + cell; r += cell) {
      context.beginPath();
      context.arc(ccx, ccy, r, 0, Math.PI * 2);
      context.stroke();
    }
  } else {
    // Rotated row/col lines, same pitch/rotation as forEachScreenDot, where a
    // screen point is (ccx + u*cos - v*sin, ccy + u*sin + v*cos).
    const a = (angle * Math.PI) / 180;
    const cos = Math.cos(a);
    const sin = Math.sin(a);
    const diag =
      Math.ceil((2 * Math.sqrt(width * width + height * height)) / cell) + 2;
    const ext = diag * cell;
    // Map (u,v) in the rotated screen space back to canvas px.
    const toXY = (u, v) => [ccx + u * cos - v * sin, ccy + u * sin + v * cos];
    for (let i = -diag; i <= diag; i++) {
      const off = i * cell;
      // Row line: v fixed at `off`, u sweeps the full extent.
      let [x0, y0] = toXY(-ext, off);
      let [x1, y1] = toXY(ext, off);
      context.beginPath();
      context.moveTo(x0, y0);
      context.lineTo(x1, y1);
      context.stroke();
      // Col line: u fixed at `off`, v sweeps the full extent.
      [x0, y0] = toXY(off, -ext);
      [x1, y1] = toXY(off, ext);
      context.beginPath();
      context.moveTo(x0, y0);
      context.lineTo(x1, y1);
      context.stroke();
    }
  }
  context.restore();
};

// Red crosshair + small circle marking the arrangement center. Drawn as a
// transient overlay while the "Center" control is being dragged.
const drawCenterGuide = (context, width, height) => {
  const [ccx, ccy] = getCenter(width, height);
  const arm = Math.max(12, width / 50);

  context.save();
  context.strokeStyle = "red";
  context.lineWidth = Math.max(1.5, width / 500);
  context.beginPath();
  context.moveTo(ccx - arm, ccy);
  context.lineTo(ccx + arm, ccy);
  context.moveTo(ccx, ccy - arm);
  context.lineTo(ccx, ccy + arm);
  context.stroke();
  context.beginPath();
  context.arc(ccx, ccy, arm / 2, 0, Math.PI * 2);
  context.stroke();
  context.restore();
};

const getColor = (x, y, pixels) => {
  const r = pixels[Math.round(x) * 4 + 0 + Math.round(y) * 4 * elCanvas.width];
  const g = pixels[Math.round(x) * 4 + 1 + Math.round(y) * 4 * elCanvas.width];
  const b = pixels[Math.round(x) * 4 + 2 + Math.round(y) * 4 * elCanvas.width];
  return [r, g, b];
};

const createPane = () => {
  pane = new Pane({
    container: paneDiv,
  });

  // --- Source: what image/video is being halftoned -------------------------
  const srcFolder = pane.addFolder({ title: "Source" });
  const btn = srcFolder.addButton({ title: "Upload" });
  btn.on("click", () => {
    inputMedia.click();
  });
  srcFolder.addInput(params, "showOriginal", { label: "Original photo" });
  srcFolder.addInput(params, "showGrid", { label: "Show grid" });

  // --- Screen: how the halftone screen is laid out over the canvas ---------
  const screenFolder = pane.addFolder({ title: "Screen" });
  screenFolder.addInput(params, "screen", {
    label: "Type",
    options: { Dots: "dot", Lines: "line" },
  });
  const arrangeInput = screenFolder.addInput(params, "arrange", {
    label: "Arrangement",
    options: { "Grid (rows/cols)": "grid", "Radial (rings)": "radial" },
  });

  // 2D pad to place the arrangement center (normalized 0..1 over the canvas).
  // The center only affects the radial rings, so it's disabled for grid.
  const centerInput = screenFolder.addInput(params, "center", {
    label: "Center",
    x: { min: 0, max: 1, step: 0.01 },
    y: { min: 0, max: 1, step: 0.01 },
    disabled: params.arrange !== "radial",
  });
  arrangeInput.on("change", (ev) => {
    centerInput.disabled = ev.value !== "radial";
  });
  // Show the red crosshair while the center changes, then hide it shortly
  // after the last change (i.e. once the user stops dragging/editing).
  centerInput.on("change", () => {
    showCenterGuide = true;
    if (centerGuideTimer) clearTimeout(centerGuideTimer);
    centerGuideTimer = setTimeout(() => {
      showCenterGuide = false;
      if (typeof manager !== "undefined") manager.render();
    }, 600);
  });

  screenFolder.addInput(params, "cellSize", {
    min: 2,
    max: 200,
    step: 1,
    label: "Cell size",
  });
  screenFolder.addInput(params, "angle", {
    min: 0,
    max: 90,
    step: 1,
    label: "Angle",
  });

  // --- Dots & tone: the shape of each mark and how big it gets -------------
  const dotsFolder = pane.addFolder({ title: "Dots & tone" });
  dotsFolder.addInput(params, "shape", {
    label: "Shape",
    options: {
      Circle: "circle",
      Square: "square",
      Triangle: "triangle",
      Diamond: "diamond",
      Star: "star",
      "Custom SVG": "custom",
    },
  });
  // Upload an SVG to use its outline as the dot shape (sets Shape to Custom).
  dotsFolder.addButton({ title: "Upload SVG shape" }).on("click", () => {
    inputSVG.click();
  });
  // How each shape is angled: radially out of the center, randomly, or a fixed
  // angle. The fixed-angle slider only matters in 'fixed' mode.
  dotsFolder.addInput(params, "shapeAngle", {
    label: "Shape angle",
    options: { "Out of center": "center", Random: "random", Fixed: "fixed" },
  });
  dotsFolder.addInput(params, "fixedAngle", {
    min: 0,
    max: 360,
    step: 1,
    label: "Fixed angle",
  });
  dotsFolder.addInput(params, "dotScale", {
    min: 0.2,
    max: 2,
    step: 0.05,
    label: "Dot scale",
  });
  dotsFolder.addInput(params, "gamma", {
    min: 0.2,
    max: 3,
    step: 0.05,
    label: "Gamma",
  });
  dotsFolder.addInput(params, "sizeBy", {
    label: "Size by",
    options: { "Bright = big": "lum", "Dark = big": "dark" },
  });
  // Decay curve reshapes the brightness->size response (linear = plain mapping).
  dotsFolder.addInput(params, "decay", {
    label: "Decay",
    options: {
      Linear: "linear",
      "quad-in": "easeInQuad",
      "quad-out": "easeOutQuad",
      "quad-in-out": "easeInOutQuad",
      "cubic-in": "easeInCubic",
      "cubic-out": "easeOutCubic",
      "cubic-in-out": "easeInOutCubic",
      "quart-in": "easeInQuart",
      "quart-out": "easeOutQuart",
      "quart-in-out": "easeInOutQuart",
      "quint-in": "easeInQuint",
      "quint-out": "easeOutQuint",
      "quint-in-out": "easeInOutQuint",
      "sine-in": "easeInSine",
      "sine-out": "easeOutSine",
      "sine-in-out": "easeInOutSine",
      "expo-in": "easeInExpo",
      "expo-out": "easeOutExpo",
      "expo-in-out": "easeInOutExpo",
      "circ-in": "easeInCirc",
      "circ-out": "easeOutCirc",
      "circ-in-out": "easeInOutCirc",
      "back-in": "easeInBack",
      "back-out": "easeOutBack",
      "back-in-out": "easeInOutBack",
      "elastic-in": "easeInElastic",
      "elastic-out": "easeOutElastic",
      "bounce-in": "easeInBounce",
      "bounce-out": "easeOutBounce",
    },
  });

  // --- 3D / Sphere: wrap the halftone screen onto a ball (drag to rotate) ---
  const sphereFolder = pane.addFolder({ title: "3D / Sphere", expanded: true });
  sphereFolder.addInput(params, "mode3D", {
    label: "Mode",
    options: { "Flat (2D)": "flat", Sphere: "sphere" },
  });
  sphereFolder.addInput(params, "sphereRadius", {
    min: 50,
    max: 600,
    step: 1,
    label: "Radius",
  });
  sphereFolder.addInput(params, "wrap", {
    min: 0.05,
    max: 2,
    step: 0.01,
    label: "Wrap",
  });
  // Rotation is driven by dragging the sphere with the mouse (no sliders).

  // --- Color: ink and paper ------------------------------------------------
  const colorFolder = pane.addFolder({ title: "Color" });
  colorFolder.addInput(params, "colorMode", {
    label: "Mode",
    options: { "Colored (from image)": "color", "Mono (single ink)": "mono" },
  });
  colorFolder.addInput(params, "inkColor", { label: "Ink color" });
  colorFolder.addInput(params, "background", { label: "Background" });

  // --- Image filters applied to the source before sampling -----------------
  folder = pane.addFolder({ title: "Filters", expanded: false });
  folder.addInput(params, "Inv", { label: "Invert" });
  folder.addInput(params, "Blur", { min: 0, max: 100, step: 0.1 });
  folder.addInput(params, "BR", {
    min: 0,
    max: 200,
    step: 1,
    label: "Brightness",
  });
  folder.addInput(params, "CR", {
    min: 0,
    max: 200,
    step: 1,
    label: "Contrast",
  });
  folder.addInput(params, "Sat", {
    min: 0,
    max: 200,
    step: 1,
    label: "Saturation",
  });

  const exp = pane.addButton({ title: "Export" });
  exp.on("click", () => {
    exportType = "save";
    manager.exportFrame();
  });

  const cop = pane.addButton({ title: "Copy to Illustrator" });
  cop.on("click", () => {
    exportType = "copy";
    manager.exportFrame();
  });

  pane.on("change", () => {
    if (typeof manager !== "undefined") {
      manager.render();
    }
  });

  const footerDiv = document.createElement("DIV");
  footerDiv.setAttribute("class", "footer");

  const footnoteDiv = document.createElement("DIV");
  footnoteDiv.setAttribute("class", "footnote");
  let codeText =
    '<img class="footer-logo" src="./assets/logo.svg" alt="Genetik Studio">' +
    '<span class="footer-text">' +
    '<span class="footer-name">by <a href="https://www.instagram.com/genetikstudio/" target="_blank" rel="noopener noreferrer">Genetik Studio</a></span>' +
    '<span class="footer-version">V' +
    ver +
    " - " +
    date +
    "</span>" +
    "</span>";
  footnoteDiv.innerHTML += codeText;

  const logoDiv = document.createElement("DIV");
  logoDiv.setAttribute("class", "logo");
  codeText =
    '<a href="https://www.instagram.com/abdohassanine/" target="_blank" rel="noopener noreferrer"><svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 16 16"><path class="icon" d="M8 0C5.829 0 5.556.01 4.703.048 3.85.088 3.269.222 2.76.42a3.917 3.917 0 0 0-1.417.923A3.927 3.927 0 0 0 .42 2.76C.222 3.268.087 3.85.048 4.7.01 5.555 0 5.827 0 8.001c0 2.172.01 2.444.048 3.297.04.852.174 1.433.372 1.942.205.526.478.972.923 1.417.444.445.89.719 1.416.923.51.198 1.09.333 1.942.372C5.555 15.99 5.827 16 8 16s2.444-.01 3.298-.048c.851-.04 1.434-.174 1.943-.372a3.916 3.916 0 0 0 1.416-.923c.445-.445.718-.891.923-1.417.197-.509.332-1.09.372-1.942C15.99 10.445 16 10.173 16 8s-.01-2.445-.048-3.299c-.04-.851-.175-1.433-.372-1.941a3.926 3.926 0 0 0-.923-1.417A3.911 3.911 0 0 0 13.24.42c-.51-.198-1.092-.333-1.943-.372C10.443.01 10.172 0 7.998 0h.003zm-.717 1.442h.718c2.136 0 2.389.007 3.232.046.78.035 1.204.166 1.486.275.373.145.64.319.92.599.28.28.453.546.598.92.11.281.24.705.275 1.485.039.843.047 1.096.047 3.231s-.008 2.389-.047 3.232c-.035.78-.166 1.203-.275 1.485a2.47 2.47 0 0 1-.599.919c-.28.28-.546.453-.92.598-.28.11-.704.24-1.485.276-.843.038-1.096.047-3.232.047s-2.39-.009-3.233-.047c-.78-.036-1.203-.166-1.485-.276a2.478 2.478 0 0 1-.92-.598 2.48 2.48 0 0 1-.6-.92c-.109-.281-.24-.705-.275-1.485-.038-.843-.046-1.096-.046-3.233 0-2.136.008-2.388.046-3.231.036-.78.166-1.204.276-1.486.145-.373.319-.64.599-.92.28-.28.546-.453.92-.598.282-.11.705-.24 1.485-.276.738-.034 1.024-.044 2.515-.045v.002zm4.988 1.328a.96.96 0 1 0 0 1.92.96.96 0 0 0 0-1.92zm-4.27 1.122a4.109 4.109 0 1 0 0 8.217 4.109 4.109 0 0 0 0-8.217zm0 1.441a2.667 2.667 0 1 1 0 5.334 2.667 2.667 0 0 1 0-5.334z"/></svg></a>';
  logoDiv.innerHTML += codeText;

  footerDiv.appendChild(footnoteDiv);
  footerDiv.appendChild(logoDiv);
  paneDiv.childNodes[0].appendChild(footerDiv);
};

// Preload the bundled default custom shape so the "Custom SVG" option works out
// of the box (an uploaded SVG still overrides it).
const loadDefaultCustomShape = async () => {
  try {
    const res = await fetch("./assets/svg/custom.svg");
    if (!res.ok) return;
    loadCustomShapeFromSVG(await res.text());
    if (typeof manager !== "undefined") manager.render();
  } catch (e) {
    /* default shape is optional; ignore if it can't be fetched */
  }
};

const start = async () => {
  createPane();
  manager = await canvasSketch(sketch, settings);
  loadDefaultCustomShape();
};
start();
