const Color = require('canvas-sketch-util/color');

export const prepareDocument = (css) => {
  const head = document.head;

  let link = document.createElement('link');
  link.type = 'text/css';
  link.rel = 'stylesheet';
  link.href = css;
  head.appendChild(link);

  const favicon = document.createElement('link');
  favicon.rel = 'icon';
  favicon.type = 'image/svg+xml';
  favicon.href = './assets/favicon.svg';
  head.appendChild(favicon);

  const parentDiv = document.createElement('DIV');
  parentDiv.setAttribute('id', 'parent');
  parentDiv.setAttribute('class', 'parent');
  document.body.appendChild(parentDiv);

  const paneDiv = document.createElement('DIV');
  paneDiv.setAttribute('id', 'paneDiv');
  paneDiv.setAttribute('class', 'paneDiv child');
  parentDiv.appendChild(paneDiv);

  const canvasDiv = document.createElement('DIV');
  canvasDiv.setAttribute('id', 'canvasDiv');
  canvasDiv.setAttribute('class', 'canvasDiv child');
  parentDiv.appendChild(canvasDiv);

  const imgWrapper = document.createElement('DIV');
  imgWrapper.setAttribute('id', 'imgWrapper');
  imgWrapper.setAttribute('class', 'image-wrapper');
  canvasDiv.appendChild(imgWrapper);

  return [paneDiv, imgWrapper];
};
export const getNext = (N, i, d) => {
  // N number of points
  // i current index
  // moving diretion: 1 => moving forward, -1 => moving backward;

  let nextIndex;
  if (d == 1) {
    nextIndex = i == N - 1 ? 0 : i + 1;
  } else {
    nextIndex = i == 0 ? N - 1 : i - 1;
  }
  return nextIndex;
};

export const getDistance = (p1, p2) => {
  const dx = p1.x - p2.x;
  const dy = p1.y - p2.y;

  return Math.sqrt(dx * dx + dy * dy);
};

export // gaussian function
const getGaussian = (a, d, c) => {
  //d the distance from the center
  //c the radius
  return a * Math.exp(-(d ** 2) / (2 * c ** 2));
};

export const closeColors = (color, palette) => {
  const [r1, g1, b1] = Color.parse(color).rgb;
  let Erorr1 = 1000;
  let closeColor;
  for (let i = 0; i < palette.length; i++) {
    const [r2, g2, b2] = Color.parse(palette[i]).rgb;
    const Erorr2 = Math.abs(r1 - r2) + Math.abs(g1 - g2) + Math.abs(b1 - b2);

    if (Erorr2 < Erorr1) {
      Erorr1 = Erorr2;
      closeColor = palette[i];
    }
  }
  return closeColor;
};

export const convColor = (color, segments) => {
  const segSize = 255 / segments;

  const [r, g, b] = Color.parse(color).rgb;

  const i = Math.round(r / segSize);
  const j = Math.round(g / segSize);
  const k = Math.round(b / segSize);

  const r2 = i * segSize;
  const g2 = j * segSize;
  const b2 = k * segSize;

  const roundColor = Color.parse([r2, g2, b2]).hex;
  const numBase4 = `${i}${j}${k}`;
  const numBase10 = convBase(numBase4, segments + 1);
  return [roundColor, numBase10];
};

export const convBase = (num, base) => {
  const digits = num.split('');
  let result = 0;
  let power = 0;

  for (let i = digits.length - 1; i >= 0; i--) {
    const digit = digits[i];
    result += digit * Math.pow(base, power);
    power++;
  }
  return result;
};

export const getColor = (x, y, elCanvas, pixels) => {
  // this function retuns the the color of a givin pixel
  const r = pixels[Math.round(x) * 4 + 0 + Math.round(y) * 4 * elCanvas.width];
  const g = pixels[Math.round(x) * 4 + 1 + Math.round(y) * 4 * elCanvas.width];
  const b = pixels[Math.round(x) * 4 + 2 + Math.round(y) * 4 * elCanvas.width];

  // return Color.parse([r, g, b]).hex;
  return [r, g, b];
};

export const getItersection = (l1, l2) => {
  const p11 = l1.p1;
  const p12 = l1.p2;

  const p21 = l2.p1;
  const p22 = l2.p2;

  //line 1 --> y1 = m1*x1 + b1;
  const m1 = (p12.y - p11.y) / (p12.x - p11.x); // slope equal dy/dx ..> perpendicular slope is -dx/dy
  const x1 = p11.x; // mid point x of first segment p1 - p2;
  const y1 = p11.y; // mid point y of first segment p1 - p2;
  const b1 = y1 - m1 * x1;

  //line 2 --> y2 = m2*x2 + b2;
  const m2 = (p22.y - p21.y) / (p22.x - p21.x); // slope equal dy/dx ..> perpendicular slope is -dx/dy
  const x2 = p21.x; // mid point x of first segment p1 - p2;
  const y2 = p21.y; // mid point y of first segment p1 - p2;
  const b2 = y2 - m2 * x2;

  //itersection between two perpendicular lines (the center of circumcircle);
  const cx = (b2 - b1) / (m1 - m2);
  const cy = (b1 * m2 - b2 * m1) / (m2 - m1);

  return { x: cx, y: cy };
};

export const drawSmoothLine = (context, points, edges = false, color = 'black', thickness = 3) => {
  context.beginPath();
  for (let i = 0; i < points.length - 1; i++) {
    const curr = points[i];
    const next = points[i + 1];

    const mx = curr.x + (next.x - curr.x) * 0.5;
    const my = curr.y + (next.y - curr.y) * 0.5;

    if (i == 0) context.moveTo(curr.x, curr.y);
    else if (i == points.length - 2) context.quadraticCurveTo(curr.x, curr.y, next.x, next.y);
    else context.quadraticCurveTo(curr.x, curr.y, mx, my);
  }

  context.lineWidth = thickness;
  context.strokeStyle = color;
  context.stroke();

  // console.log(edges);
  if (edges) {
    context.beginPath();
    context.moveTo(points[0].x, points[0].y);
    for (let i = 0; i < points.length; i++) {
      const curr = points[i];
      context.lineTo(curr.x, curr.y);
    }

    context.lineWidth = thickness / 2;
    context.strokeStyle = 'cyan';
    context.stroke();

    points.forEach((point) => {
      context.fillStyle = 'cyan';
      point.draw(context);
    });
  }
};
